const raw = $input.first().json;
const xmlText = (typeof raw === 'string' ? raw : JSON.stringify(raw)) || '';

if (!xmlText.includes('<item')) return [{ json: { _empty: true } }];

const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/gi;
const titleRegex = /<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/i;
const linkRegex = /<link>([\s\S]*?)<\/link>/i;
const descRegex = /<description[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/description>/i;

const results = [];
let match;

while ((match = itemRegex.exec(xmlText)) !== null) {
  const xml = match[1];
  const title = (titleRegex.exec(xml)?.[1] || '').trim();
  const link  = (linkRegex.exec(xml)?.[1] || '').trim();
  const desc  = (descRegex.exec(xml)?.[1] || '').replace(/<[^>]*>/g, '').trim();

  if (!title) continue;

  const combined = (title + ' ' + desc).toLowerCase();
  // Decode HTML entities before matching to avoid false positives on CSS class names
  const decoded = combined.replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&amp;/g,'&').replace(/&quot;/g,'"');
  // Strip any remaining tags after decode
  const clean = decoded.replace(/<[^>]*>/g, ' ');
  const keywords = ['claude code', 'claude coding', 'anthropic claude', 'claude ai'];
  if (!keywords.some(kw => clean.includes(kw))) continue;

  const rawId = link.replace(/[^a-z0-9]/gi, '').substring(0, 40);

  results.push({
    title,
    source: 'WeWorkRemotely',
    url: link,
    description: desc.substring(0, 500),
    date_found: new Date().toISOString(),
    company: null,
    dedup_key: 'wwr_' + rawId
  });
}

if (results.length === 0) return [{ json: { _empty: true } }];
return results.map(r => ({ json: r }));

const raw = $input.first().json;
const html = (typeof raw === 'string' ? raw : (raw.data || JSON.stringify(raw))) || '';

if (!html.includes('/jobseekers/job/')) return [{ json: { _empty: true } }];

const results = [];
const seen = new Set();

// Split HTML by job anchor links — each chunk starts with the URL slug
const chunks = html.split('<a href="/jobseekers/job/');

for (let i = 1; i < chunks.length; i++) {
  const chunk = chunks[i];

  // Extract URL slug (everything up to the closing quote)
  const slugMatch = chunk.match(/^([^"]+)"/);
  if (!slugMatch) continue;
  const slug = slugMatch[1];

  if (seen.has(slug)) continue;
  seen.add(slug);

  // Extract title from <h4> — strip nested <span> badges
  const titleMatch = chunk.match(/<h4[^>]*>([\s\S]*?)<\/h4>/i);
  if (!titleMatch) continue;
  const title = titleMatch[1].replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
  if (!title) continue;

  // Extract short description snippet
  const descMatch = chunk.match(/<div[^>]*class="[^"]*desc[^"]*"[^>]*>([\s\S]*?)<\/div>/i);
  const desc = descMatch
    ? descMatch[1].replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim().substring(0, 500)
    : null;

  // Extract salary
  const salaryMatch = chunk.match(/<dd[^>]*class="col"[^>]*>([\s\S]*?)<\/dd>/i);
  const salary = salaryMatch ? salaryMatch[1].replace(/<[^>]*>/g, '').trim() : null;

  const url = 'https://www.onlinejobs.ph/jobseekers/job/' + slug;
  const rawId = slug.replace(/[^a-z0-9]/gi, '').substring(0, 40);

  results.push({
    title,
    source: 'OnlineJobsPH',
    url,
    description: salary && desc
      ? `Salary: ${salary} | ${desc}`
      : (desc || salary || null),
    date_found: new Date().toISOString(),
    company: null,
    dedup_key: 'ojph_' + rawId
  });
}

if (results.length === 0) return [{ json: { _empty: true } }];
return results.map(r => ({ json: r }));

const allItems = $input.all();
const leads = [];

for (const item of allItems) {
  const d = item.json;
  if (d._empty === true) continue;
  if (!d.title || !d.source || !d.url || !d.dedup_key) continue;
  leads.push(d);
}

if (leads.length === 0) {
  return [{ json: { _no_leads: true, message: 'No relevant leads found this run.' } }];
}

return leads.map(l => ({ json: l }));

// Collapse all incoming lead items into a single trigger item
// so that Fetch Existing Dedup Keys only runs once (prevents 429 rate limit)
return [{ json: { _trigger: true } }];

const xanoRecords = $input.first().json;
const records = Array.isArray(xanoRecords)
  ? xanoRecords
  : (xanoRecords.items || xanoRecords.data || []);

const existingKeys = new Set(records.map(r => r.dedup_key).filter(Boolean));
return [{ json: { existingKeys: Array.from(existingKeys) } }];

const newLeadItems = $input.all().filter(i => i.json.dedup_key !== undefined);
const keySetItem = $input.all().find(i => i.json.existingKeys !== undefined);

const existingKeys = new Set(
  keySetItem ? (keySetItem.json.existingKeys || []) : []
);

const seen = new Set();
const finalLeads = [];

for (const item of newLeadItems) {
  const lead = item.json;
  if (!lead.dedup_key) continue;
  if (existingKeys.has(lead.dedup_key)) continue;
  if (seen.has(lead.dedup_key)) continue;
  seen.add(lead.dedup_key);
  finalLeads.push(lead);
}

if (finalLeads.length === 0) {
  return [{ json: { _all_duplicates: true, message: 'All leads are already in Xano.' } }];
}

return finalLeads.map(l => ({ json: l }));

// Aggregate all lead items into a single batch payload
const leads = $input.all().map(i => i.json);
return [{ json: { leads } }];

const res = $input.first().json;
return [{
  json: {
    status: 'success',
    leads_saved: res.saved_count ?? 0,
    leads_skipped: res.skipped_count ?? 0,
    run_at: new Date().toISOString(),
    message: `Saved ${res.saved_count ?? 0} new Claude Code job lead(s) to Xano.`
  }
}];

return [{
  json: {
    status: 'no_new_leads',
    run_at: new Date().toISOString(),
    message: 'Run complete. No new Claude Code leads found or all were duplicates.'
  }
}];
